const items = $input.all();
return items.map(item => {
  const d = item.json;
  if (d.bot_id) return null;
  return {
    json: {
      channel: 'slack',
      sender_id: d.user || 'unknown',
      sender_name: d.user_profile?.real_name || d.user || 'unknown',
      body: d.text || '',
      raw_metadata: JSON.stringify({ channel: d.channel, ts: d.ts, thread_ts: d.thread_ts }),
      status: 'unread'
    }
  };
}).filter(Boolean);
